import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"盈亏分析","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/pnl.md","filePath":"zh-CN/portfolio-and-statements/pnl.md"}'),i={name:"portfolio-and-statements/pnl.md"};function o(h,a,d,n,p,s){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="盈亏分析" tabindex="-1">盈亏分析 <a class="header-anchor" href="#盈亏分析" aria-label="Permalink to &quot;盈亏分析&quot;">​</a></h1><p>盈亏分析页展示账户累计盈亏、个股收益明细和资产变动，支持简单加权与时间加权两种收益率算法。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ul><li>点击资产总览页面的空白处，选择「盈亏分析」</li><li>长桥 App → 资产 → 全部功能 → 盈亏分析</li></ul><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><ul><li><strong>累计盈亏</strong>：账户因交易或企业行动引起的盈亏总额</li><li><strong>累计收益率</strong>：支持简单加权和时间加权两种计算方式</li><li><strong>跑赢指数</strong>：与大盘指数的对比情况</li><li><strong>每日收益</strong>：按日展示收益明细（收益日历）</li><li><strong>个股收益</strong>：各标的盈亏明细，实时更新</li><li><strong>资产变动</strong>：资金存取、转仓等资产变动记录</li></ul><h2 id="盈亏字段说明" tabindex="-1">盈亏字段说明 <a class="header-anchor" href="#盈亏字段说明" aria-label="Permalink to &quot;盈亏字段说明&quot;">​</a></h2><h3 id="累计盈亏" tabindex="-1">累计盈亏 <a class="header-anchor" href="#累计盈亏" aria-label="Permalink to &quot;累计盈亏&quot;">​</a></h3><p>累计盈亏统计因交易或企业行动等引起的账户盈亏总额。</p><p>累计盈亏 = 期间每日盈亏合计</p><p>每日盈亏 = 期末总资产 − 期初总资产 − 期间净投入</p><p>由于长桥为综合账户，计算盈亏时统一折算为港币。汇率波动可能导致即使无任何交易，盈亏金额也会变动。</p><p>期末 / 期初总资产（HKD 等值）= 美元总资产 × 对应汇率 + 港币总资产 × 对应汇率</p><p>期间净投入（以下业务作为投入，不记入盈亏）：出入金、主子账户转账、转仓、主子账户转仓、兑换、融资利息、现金卡奖励。</p><h3 id="持仓盈亏-浮动盈亏" tabindex="-1">持仓盈亏（浮动盈亏） <a class="header-anchor" href="#持仓盈亏-浮动盈亏" aria-label="Permalink to &quot;持仓盈亏（浮动盈亏）&quot;">​</a></h3><p>从开仓至今的累计盈亏，不含手续费。</p><ul><li>多头持仓盈亏 =（现价 − 成本）× 当前数量</li><li>空头持仓盈亏 =（成本 − 现价）× 当前数量</li></ul><p>成本计算方式见下方「持仓成本」章节。</p><h3 id="当日盈亏" tabindex="-1">当日盈亏 <a class="header-anchor" href="#当日盈亏" aria-label="Permalink to &quot;当日盈亏&quot;">​</a></h3><p>从上一交易日收盘价到当前时段的累计盈亏。</p><p>计算公式：当日盈亏 = 最新价 × 当前持仓数量 − 昨收价 × 昨收持仓数量 + 当日卖出成交额 − 当日买入成交额</p><p>港股：根据香港时间 T 日 9 点～T+1 日 9 点之间的股价变更及交易行为计算。</p><p>美股受盘前盘后、夜盘开关影响：</p><table tabindex="0"><thead><tr><th>盘前盘后</th><th>夜盘</th><th>最新价范围</th><th>统计周期（美东时间）</th></tr></thead><tbody><tr><td>开启</td><td>开启</td><td>含盘前盘后价</td><td>T 日 20:00 ～ T+1 日 20:00</td></tr><tr><td>开启</td><td>关闭</td><td>含盘前盘后价（夜盘取盘后价）</td><td>T 日 04:00 ～ T+1 日 04:00</td></tr><tr><td>关闭</td><td>开启</td><td>不含盘前盘后价</td><td>T 日 20:00 ～ T+1 日 20:00</td></tr><tr><td>关闭</td><td>关闭</td><td>仅昨收价和盘中价</td><td>T 日 04:00 ～ T+1 日 04:00</td></tr></tbody></table><p>当日盈亏只计算实际持仓数据，手续费不计入。</p><h2 id="收益率计算方法" tabindex="-1">收益率计算方法 <a class="header-anchor" href="#收益率计算方法" aria-label="Permalink to &quot;收益率计算方法&quot;">​</a></h2><h3 id="简单加权" tabindex="-1">简单加权 <a class="header-anchor" href="#简单加权" aria-label="Permalink to &quot;简单加权&quot;">​</a></h3><p>简单加权 = 累计收益率 = 累计收益 ÷（期初总资产 + 期间净流入）</p><p>将统计区间内的资金存取、股票转仓等净流入金额全部视为在期初发生，合并为投入成本。</p><p>优点：计算快速，简单易懂。</p><p>缺点：计算区间较长或资金存取较大时，可能导致收益率扭曲，甚至出现负数，失去参考价值。</p><h3 id="时间加权收益率" tabindex="-1">时间加权收益率 <a class="header-anchor" href="#时间加权收益率" aria-label="Permalink to &quot;时间加权收益率&quot;">​</a></h3><p>时间加权收益率 = [（1 + 第 1 日当日收益率）×（1 + 第 2 日当日收益率）× … ×（1 + 第 n 日当日收益率）− 1] × 100%</p><p>当日收益率 = 当日盈亏额 ÷（昨日期末资产 + 当日净投入）</p><p>将整个区间按天分割，先计算每天的收益率，最后计算区间累计收益率。</p><p>优点：尽量减少净流入对收益率的影响。</p><p>缺点：频繁大额资金存取时，可能导致收益金额与收益率符号相反，此时收益率无参考价值。</p><h2 id="收益日历" tabindex="-1">收益日历 <a class="header-anchor" href="#收益日历" aria-label="Permalink to &quot;收益日历&quot;">​</a></h2><p>收益日历分币种计算盈亏后合计，不受汇率变化影响，反映真实盈亏情况。</p><p>计算逻辑：先计算每个币种的盈亏，再合计并转化为港币。</p><p>A 币种盈亏 = 期末总资产（T 日）− 期初总资产（T-1 日）− 当日净投入</p><p>当日盈亏 = A 币种盈亏 × A 币种汇率 + … + N 币种盈亏 × N 币种汇率</p><p>收益日历显示的盈亏与资产页当日盈亏口径不同（见下方常见问题）。</p><h2 id="持仓成本" tabindex="-1">持仓成本 <a class="header-anchor" href="#持仓成本" aria-label="Permalink to &quot;持仓成本&quot;">​</a></h2><p>持仓成本决定持仓盈亏的计算基准。长桥支持两种成本价计算方式，可在「资产首页」→「全部功能」→「资产设置」→「成本计算方式」切换。</p><h3 id="摊薄成本" tabindex="-1">摊薄成本 <a class="header-anchor" href="#摊薄成本" aria-label="Permalink to &quot;摊薄成本&quot;">​</a></h3><p>代表开仓至平仓整个持有期内的保本价格。每次加仓或减仓都可能摊高或摊低成本价，同时考虑买入、卖出及企业行动现金分红的变化。</p><ul><li>多头：摊薄成本 =（持有期买入总金额 − 持有期卖出总金额 − 持有期现金分红）÷ 当前持有数量</li><li>空头：摊薄成本 =（持有期卖出总金额 − 持有期买入总金额 − 持有期现金分红）÷ 当前持有数量</li></ul><p>更新逻辑：买卖后实时更新。</p><h3 id="平均开仓成本" tabindex="-1">平均开仓成本 <a class="header-anchor" href="#平均开仓成本" aria-label="Permalink to &quot;平均开仓成本&quot;">​</a></h3><p>只考虑加仓情况，不考虑减仓。已减仓的部分转为已实现盈亏。</p><p>平均开仓成本 =（开仓前平均成本 × 开仓前数量 + 本次开仓金额）÷ 买入后持有数量</p><p>更新逻辑：仅开仓成功时更新（多头买入开仓、空头卖出开仓），平仓或减仓不更新。</p><h3 id="成本计算统一规则" tabindex="-1">成本计算统一规则 <a class="header-anchor" href="#成本计算统一规则" aria-label="Permalink to &quot;成本计算统一规则&quot;">​</a></h3><ul><li>日内同一方向的交易（如日内做多清仓后再建仓）：系统视为做 T，延续持有期数据计算成本。</li><li>日内不同方向的交易（如日内做空 - 平仓 - 做多）：清仓后成本清空，再次建仓重新开始计算。</li></ul><p>注意：发生公司行动或转股时，成本价和盈亏的计算可能不准确，但不会影响实际资产。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="当天除净后股票出现亏损" tabindex="-1">当天除净后股票出现亏损 <a class="header-anchor" href="#当天除净后股票出现亏损" aria-label="Permalink to &quot;当天除净后股票出现亏损&quot;">​</a></h3><p>按最新价计算当前持仓总市值下降，但派息在除净之后入账，入账后成本才会减少，此阶段显示亏损属正常情况。</p><h3 id="持仓盈亏与当日盈亏对不上" tabindex="-1">持仓盈亏与当日盈亏对不上 <a class="header-anchor" href="#持仓盈亏与当日盈亏对不上" aria-label="Permalink to &quot;持仓盈亏与当日盈亏对不上&quot;">​</a></h3><p>持仓盈亏是从开仓后累计的盈亏，与成本价相关；当日盈亏代表当日市值对比昨日市值的价差，与昨收价相关。两者统计口径不同，不应直接对比。</p><h3 id="股票卖出后再卖空-成本和盈亏没对上" tabindex="-1">股票卖出后再卖空，成本和盈亏没对上 <a class="header-anchor" href="#股票卖出后再卖空-成本和盈亏没对上" aria-label="Permalink to &quot;股票卖出后再卖空，成本和盈亏没对上&quot;">​</a></h3><p>换了仓位方向后，盈亏会重计，相当于之前仓位方向已平仓，不会继承多头的成本。</p><h3 id="盈亏排行中跟个股盈亏累计对不上" tabindex="-1">盈亏排行中跟个股盈亏累计对不上 <a class="header-anchor" href="#盈亏排行中跟个股盈亏累计对不上" aria-label="Permalink to &quot;盈亏排行中跟个股盈亏累计对不上&quot;">​</a></h3><p>统计更新频率不同：盈亏排行是离线数据，每天更新一次；个股盈亏明细是实时数据，实时更新。</p><h3 id="总盈亏不等于期末总资产-−-期初总资产" tabindex="-1">总盈亏不等于期末总资产 − 期初总资产 <a class="header-anchor" href="#总盈亏不等于期末总资产-−-期初总资产" aria-label="Permalink to &quot;总盈亏不等于期末总资产 − 期初总资产&quot;">​</a></h3><p>由于为综合账户，期初期末资产统一折算为港币，但盈亏额不考虑汇率变化。</p><p>示例：入金 10000 USD，期初汇率 7.8，期初资产为 78000 HKD；无任何交易，期末汇率 7.82，期末资产为 78200 HKD，但盈亏实际为 0。</p><h3 id="收益日历与资产页当日盈亏不相等" tabindex="-1">收益日历与资产页当日盈亏不相等 <a class="header-anchor" href="#收益日历与资产页当日盈亏不相等" aria-label="Permalink to &quot;收益日历与资产页当日盈亏不相等&quot;">​</a></h3><p>收益日历：拿当天实时资产 − 日初总资产计算。日初总资产 = 美东 20 点（夏令时北京时间早 8 点，冬令时早 9 点）的合计现金 + 合计持仓市值（使用港美股收盘价）。</p><p>资产页当日盈亏：（当前价格 × 当前数量）−（昨日收盘价 × 昨日收盘数量）+ 当日卖出成交额 − 当日买入成交额。按市场分开：当日盈亏 = 当天港股盈亏 + 昨日美股盈亏 + 基金盈亏，其中美股盈亏根据盘前盘后价设置自动调整。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/portfolio-and-statements">资产与账单</a></li></ul>',73)])])}const b=t(i,[["render",o]]);export{c as __pageData,b as default};
